import React, { useState } from 'react';

const App = () => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [tasks, setTasks] = useState(['Task 1', 'Task 2']);

  const handleSubmit = (e) => {
    e.preventDefault();

    if (username && password) {
      setTasks([...tasks, `New Task ${tasks.length + 1}`]);
    }
  }

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <form onSubmit={handleSubmit} className="w-full max-w-md bg-white p-4 shadow-md">
        <label className="block mb-2"><input type="text" value={username} onChange={(e) => setUsername(e.target.value)} className="block w-full p-2 mb-4 border border-gray-400" placeholder="Username"/></label>
        <label className="block mb-2"><input type="password" value={password} onChange={(e) => setPassword(e.target.value)} className="block w-full p-2 mb-4 border border-gray-400" placeholder="Password"/></label>
        <button type="submit" className="bg-[#411C56] hover:bg-[#C06C88] text-white font-bold py-2 px-4 rounded">Submit</button>
      </form>
      <div className="mt-4 bg-white p-4 shadow-md w-full max-w-md">
        <h2 className="text-lg font-bold mb-2">Tasks</h2>
        <ul>
          {tasks.map((task, index) => (
            <li key={index} className="mb-2">{task}</li>
          ))}
        </ul>
      </div>
    </div>
  );
};

export default App;
